ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?cardfees a :CardFees .
    ?products a :Products .
    ?cardfees p:hasProducts ?products .
    ?cardfees p:Fee ?fee .
    ?products p:Type ?type_f .
    FILTER(STR(?type_f) = "Credit Card")
    BIND(?fee AS ?o0)
  }
  UNION
  {
    ?monthlyinterestrates a :MonthlyInterestRates .
    ?products a :Products .
    ?monthlyinterestrates p:hasProducts ?products .
    ?monthlyinterestrates p:Rate ?rate .
    ?products p:Type ?type_f .
    FILTER(STR(?type_f) = "Credit Card")
    BIND(?rate AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?cardfees a :CardFees .
    ?products a :Products .
    ?cardfees p:hasProducts ?products .
    ?cardfees p:Fee ?fee .
    BIND(?fee AS ?o0)
  }
  UNION
  {
    ?monthlyinterestrates a :MonthlyInterestRates .
    ?products a :Products .
    ?monthlyinterestrates p:hasProducts ?products .
    ?monthlyinterestrates p:Rate ?rate .
    ?products p:Type ?type_f .
    FILTER(STR(?type_f) = "Credit Card")
    BIND(?rate AS ?o0)
  }
} }
}
